// Build Seed Config v1.0
// Validación de input y generación de slots

const tomorrow = new Date();
tomorrow.setDate(tomorrow.getDate() + 1);
const date = tomorrow.toISOString().split('T')[0];

// Slots horarios (09:00 - 16:00)
const slots = ['09:00', '10:00', '11:00', '12:00', '13:00', '14:00', '15:00', '16:00'];

// Regex whitelist para validación (SEC04)
const nameRegex = /^[A-Za-z\s]+$/;
const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

return slots.map((time, i) => {
  const chat_id = 9800000 + i;
  const user_name = 'Seed Patient ' + String.fromCharCode(65 + i);
  const user_email = 'seed@test.local';

  // Validación de input (SEC04)
  if (!nameRegex.test(user_name)) {
    throw new Error(`Invalid user_name format: ${user_name}`);
  }
  if (!emailRegex.test(user_email)) {
    throw new Error(`Invalid user_email format: ${user_email}`);
  }

  return {
    json: {
      provider_id: 1,
      service_id: 1,
      start_time: `${date}T${time}:00.000-03:00`,
      chat_id: chat_id,
      user_name: user_name,
      user_email: user_email,
      _meta: {
        slot_index: i,
        generated_at: new Date().toISOString()
      }
    }
  };
});

// Standard Contract Output v1.0
// Agrega _meta consistente y versionado

const input = $input.first().json;

return [{
  json: {
    success: input.success || false,
    error_code: input.error_code || null,
    error_message: input.error_message || null,
    data: input.data || {
      total_slots: input.total_slots || 0,
      successful_bookings: input.successful_bookings || 0,
      failed_bookings: input.failed_bookings || 0
    },
    _meta: {
      source: 'SEED_BOOK_TOMORROW',
      workflow_id: 'HxMojMqbRiNgquvd',
      timestamp: new Date().toISOString(),
      version: '1.0.0'
    }
  }
}];

// Error Handler: Format error to Standard Contract
const error = $input.first().json;
const nodeName = error.nodeName || 'Unknown';

return [{
  json: {
    success: false,
    error_code: error.error_code || 'SEED_WORKFLOW_ERROR',
    error_message: `Error en ${nodeName}: ${error.message || 'Error desconocido'}`,
    data: null,
    _meta: {
      source: 'SEED_ERROR_HANDLER',
      workflow_id: 'HxMojMqbRiNgquvd',
      timestamp: new Date().toISOString(),
      version: '1.0.0',
      error_node: nodeName
    }
  }
}];
